={{ (() => {
const body = $json.body || {};
const url = body.url || '';
const source = body.source || 'auto';
const transcriber = body.transcriber || 'assemblyai';
const gdrive_file_id = body.gdrive_file_id || '';
const callback_url = body.callback_url || '';

let detectedSource = source;
if (source === 'auto' && url) {
  if (url.includes('youtube.com') || url.includes('youtu.be')) {
    detectedSource = 'youtube';
  } else if (url.includes('drive.google.com')) {
    detectedSource = 'gdrive';
  } else {
    detectedSource = 'social';
  }
}
if (gdrive_file_id) detectedSource = 'gdrive';

return JSON.stringify({ url, source: detectedSource, transcriber, gdrive_file_id, callback_url });
})() }}

